impl Rlm {
    pub fn new(config: RlmConfig) -> Self {
        let llm = LlmClient::new(config.client.clone(), &config.model);
        Self {
            config,
            llm,
            usage: Mutex::new(TrajectoryUsage::default()),
        }
    }

    pub async fn completion(&self, query: &str, context: &str) -> Result<String> {
        let (answer, _) = self.completion_with_telemetry(query, context).await?;
        Ok(answer)
    }

    fn record_trajectory(
        &self,
        query: &str,
        context: &str,
        messages: &[Message],
        telemetry: &DepthTelemetry,
        final_answer: &str,
    ) {
        if let Some(sink) = self.config.trace_sink.as_ref() {
            let usage = self.usage.lock().map(|g| g.clone()).unwrap_or_default();
            let traj = Trajectory {
                trace_id: new_trace_id(),
                timestamp: rfc3339_now(),
                query: query.to_string(),
                context_chars: context.chars().count(),
                model: self.config.model.clone(),
                sub_model: self.config.sub_model.clone(),
                depth: self.config.depth,
                max_depth: self.config.max_depth,
                max_iterations: self.config.max_iterations,
                policy_profile: self.config.runtime_policy.profile_name.clone(),
                final_answer: final_answer.to_string(),
                messages: messages.to_vec(),
                telemetry: TrajectoryTelemetry::from(telemetry),
                usage,
            };
            if let Err(e) = sink.record(&traj) {
                if self.config.verbose {
                    eprintln!("[altum] trajectory record failed: {}", e);
                }
            }
        }
    }

    fn accumulate_usage(&self, prompt: Option<i32>, completion: Option<i32>, total: Option<i32>) {
        if let Ok(mut g) = self.usage.lock() {
            g.add(prompt, completion, total);
        }
    }

    async fn completion_with_telemetry(
        &self,
        query: &str,
        context: &str,
    ) -> Result<(String, DepthTelemetry)> {
        self.validate_depth_policy_feasibility()?;
        let mut sandbox = Sandbox::new(&self.config.tool_registry)?;
        let mut runtime = RuntimeState::new(context);
        let mut telemetry = DepthTelemetry::new(self.config.depth);

        let mut effective_context = context.to_string();
        if self.config.runtime_policy.inject_policy_into_context {
            effective_context = self.config.runtime_policy.prepend_to_context(context);
        }

        if !effective_context.is_empty() {
            sandbox.set_variable("context", Object::String(effective_context))?;
        }

        let mut messages =
            prompts::build_system_prompt(self.config.depth, &self.config.tool_registry);
        if let Some(policy_block) = self.config.runtime_policy.prompt_instruction_block() {
            messages.push(Message::system(&policy_block));
        }

        for iteration in 0..self.config.max_iterations {
            messages.push(prompts::next_action_prompt(query, iteration, false));

            let prompt_chars: usize = messages.iter().map(|m| m.content.len()).sum();
            let completion = self.llm.completion(&messages).await?;
            self.accumulate_usage(
                completion.usage.prompt_tokens,
                completion.usage.completion_tokens,
                completion.usage.total_tokens,
            );
            let response = completion.text;

            if self.config.verbose {
                eprintln!(
                    "[depth={}][iter={}/{}] response: {} chars",
                    self.config.depth,
                    iteration + 1,
                    self.config.max_iterations,
                    response.len()
                );
                eprintln!(
                    "[depth={}][iter={}/{}] usage: prompt_tokens={} completion_tokens={} total_tokens={} prompt_chars={}",
                    self.config.depth,
                    iteration + 1,
                    self.config.max_iterations,
                    completion.usage.prompt_tokens.unwrap_or(0),
                    completion.usage.completion_tokens.unwrap_or(0),
                    completion.usage.total_tokens.unwrap_or(0),
                    prompt_chars
                );
            }

            let code_blocks = find_code_blocks(&response);
            messages.push(Message::assistant(&response));

            if !code_blocks.is_empty() {
                for (idx, code) in code_blocks.iter().enumerate() {
                    if self.config.trace_sandbox {
                        eprintln!(
                            "[depth={}][iter={}/{}][sandbox][block={}] code:\n{}",
                            self.config.depth,
                            iteration + 1,
                            self.config.max_iterations,
                            idx + 1,
                            code
                        );
                    }
                    let result = self
                        .execute_in_sandbox(&mut sandbox, code, &mut runtime, &mut telemetry)
                        .await?;
                    if let Some(fork) = runtime.active_fork_mut() {
                        fork.code_blocks.push(code.to_string());
                    }
                    let formatted = format_exec_result(code, &result);
                    messages.push(Message::user(&formatted));
                }
            }

            if let Some(answer) = check_final_answer(&response, &sandbox) {
                if let Some(reason) = self.depth_policy_unmet_reason(&telemetry) {
                    if self.config.runtime_policy.depth_enforcement == DepthEnforcementMode::Strict
                    {
                        if iteration + 1 < self.config.max_iterations {
                            messages.push(Message::user(&format!(
                                "Policy requirement not met: {}. Continue with recursive llm_query calls before FINAL(...).",
                                reason
                            )));
                            continue;
                        }
                        anyhow::bail!("Depth policy unmet: {}", reason);
                    }
                }
                if self.config.verbose {
                    eprintln!(
                        "[depth={}] FINAL: {}...",
                        self.config.depth,
                        &answer[..answer.len().min(120)]
                    );
                }
                let answer = strip_final_wrapper(&answer);
                self.record_trajectory(query, context, &messages, &telemetry, &answer);
                return Ok((answer, telemetry));
            }
        }

        messages.push(prompts::next_action_prompt(
            query,
            self.config.max_iterations,
            true,
        ));
        let completion = self.llm.completion(&messages).await?;
        self.accumulate_usage(
            completion.usage.prompt_tokens,
            completion.usage.completion_tokens,
            completion.usage.total_tokens,
        );
        let response = completion.text;
        messages.push(Message::assistant(&response));

        // Execute any repl code blocks in the fallback response before extracting.
        let fallback_code_blocks = find_code_blocks(&response);
        for code in &fallback_code_blocks {
            if let Ok(result) = self
                .execute_in_sandbox(&mut sandbox, code, &mut runtime, &mut telemetry)
                .await
            {
                messages.push(Message::user(&format_exec_result(code, &result)));
            }
        }

        if let Some(answer) = check_final_answer(&response, &sandbox) {
            if let Some(reason) = self.depth_policy_unmet_reason(&telemetry) {
                if self.config.runtime_policy.depth_enforcement == DepthEnforcementMode::Strict {
                    anyhow::bail!("Depth policy unmet: {}", reason);
                }
            }
            let answer = strip_final_wrapper(&answer);
            self.record_trajectory(query, context, &messages, &telemetry, &answer);
            return Ok((answer, telemetry));
        }
        if let Some(reason) = self.depth_policy_unmet_reason(&telemetry) {
            if self.config.runtime_policy.depth_enforcement == DepthEnforcementMode::Strict {
                anyhow::bail!("Depth policy unmet: {}", reason);
            }
        }
        let answer = strip_final_wrapper(&response);
        self.record_trajectory(query, context, &messages, &telemetry, &answer);
        Ok((answer, telemetry))
    }

    fn validate_depth_policy_feasibility(&self) -> Result<()> {

                stats.kept,
                stats.skipped_no_final,
                stats.skipped_too_few_messages,
                stats.skipped_truncated_messages,
                output.display()
            );
        }
    }

    Ok(())
}

fn make_rlm(client: &Client, cli: &Cli, depth: usize, runtime_policy: RuntimePolicy) -> Rlm {
    let trace_sink = cli
        .trace_output
        .as_ref()
        .map(|p| TrajectoryRecorder::to_path(p))
        .transpose()
        .ok()
        .flatten()
        .map(std::sync::Arc::new);
    Rlm::new(RlmConfig {
        client: client.clone(),
        model: cli.model.clone(),
        sub_model: cli.sub_model.clone(),
        max_iterations: cli.max_iterations,
        depth,
        max_depth: cli.max_depth,
        verbose: cli.verbose,
        trace_sandbox: cli.trace_sandbox,
        runtime_policy,
        tool_registry: std::sync::Arc::new(ToolRegistry::new()),
        trace_sink,
    })
}

fn models_url_for_base_url(base_url: &str) -> String {
    let trimmed = base_url.trim_end_matches('/');
    format!("{trimmed}/models")
}

/// Read JSONL trajectories from `input` and export SFT examples to `output`
/// according to `opts`. Returns aggregate stats.
pub fn export_sft<P1: AsRef<Path>, P2: AsRef<Path>>(
    input: P1,
    output: P2,
    opts: &ExportOptions,
) -> Result<ExportStats> {
    let input = input.as_ref();
    let output = output.as_ref();
    if let Some(parent) = output.parent() {
        if !parent.as_os_str().is_empty() {
            std::fs::create_dir_all(parent)
                .with_context(|| format!("creating output parent dir {}", parent.display()))?;
        }
    }
    let body = std::fs::read_to_string(input)
        .with_context(|| format!("reading trajectories from {}", input.display()))?;
    let trajectories = parse_trajectory_jsonl(&body)?;
    let stats = ExportStats {
        read: trajectories.len(),
        kept: 0,
        skipped_no_final: 0,
        skipped_too_few_messages: 0,
        skipped_truncated_messages: 0,
    };
    let file = File::create(output)
        .with_context(|| format!("creating output file {}", output.display()))?;
    let mut writer = BufWriter::new(file);
    let mut stats = stats;
    for traj in &trajectories {
        if opts.require_final && traj.final_answer.trim().is_empty() {
            stats.skipped_no_final += 1;
            continue;
        }
        if traj.messages.len() < opts.min_messages {
            stats.skipped_too_few_messages += 1;
            continue;
        }
        let example = build_openai_example(traj, opts);
        if let Some(max) = opts.max_messages {
            if example.messages.len() > max {
                stats.skipped_truncated_messages += 1;
                continue;
            }
        }
        let line = serde_json::to_string(&example)?;
        writer.write_all(line.as_bytes())?;
        writer.write_all(b"\n")?;
        stats.kept += 1;
    }
    writer.flush()?;
    Ok(stats)
}

pub fn parse_trajectory_jsonl(body: &str) -> Result<Vec<Trajectory>> {
    let mut out = Vec::new();
    for (idx, line) in body.lines().enumerate() {
        let trimmed = line.trim();
        if trimmed.is_empty() {
            continue;
        }
        let traj: Trajectory = serde_json::from_str(trimmed)
            .with_context(|| format!("parsing trajectory line {}", idx + 1))?;
        out.push(traj);
    }
    Ok(out)
